import json

# Create the query string for MongoDB to get all articles by Amy Jones in smaller batches
# Instead of $in (which might have issues), let's use a range query

query1 = '''
{
  "collection": "articles",
  "filter": {
    "article_id": {
      "$gte": "180",
      "$lt": "220"
    }
  },
  "projection": {
    "_id": 0,
    "article_id": 1,
    "title": 1,
    "description": 1
  }
}
'''

result = {"next_query": query1, "explanation": "Using range query to avoid potential $in issues"}
print("__RESULT__:")
print(json.dumps(result))

